import { Text, View } from 'react-native';
import React, { useState, useMemo } from 'react';

import { useKangurMobileI18n, type KangurMobileCopy } from '../i18n/kangurMobileI18n';
import {
  BASE_TONE,
  INDIGO_TONE,
  OutlineLink,
  PrimaryButton,
  SectionCard,
  StatusPill,
  SUCCESS_TONE,
  WARNING_TONE,
} from '../shared/KangurAssessmentUi';
import { KangurMobileScrollScreen } from '../shared/KangurMobileUi';
import {
  ChoiceButton,
  formatPointsLabel,
  formatQuestionCount,
  formatQuestionProgress,
  formatSuiteMeta,
  resolveQuestionStatusTone,
  RESULTS_ROUTE,
} from './tests-primitives';
import {
  useKangurMobileTests,
  type KangurMobileTestSuiteItem,
} from './useKangurMobileTests';

const TestPlayerResultsView = ({
  score,
  maxScore,
  scorePercent,
  summaryTone,
  onBackToCatalog,
  copy,
}: {
  score: number;
  maxScore: number;
  scorePercent: number;
  summaryTone: { backgroundColor: string; borderColor: string; textColor: string };
  onBackToCatalog: () => void;
  copy: KangurMobileCopy;
}): React.JSX.Element => (
  <SectionCard title={copy({ de: 'Testergebnis', en: 'Test result', pl: 'Wynik testu' })}>
    <View style={{ alignItems: 'center', gap: 12, paddingVertical: 12 }}>
      <StatusPill
        label={copy({ de: 'Test abgeschlossen', en: 'Test finished', pl: 'Test zakończony' })}
        tone={summaryTone}
      />
      <Text style={{ color: '#0f172a', fontSize: 32, fontWeight: '800' }}>
        {`${scorePercent}%`}
      </Text>
      <Text style={{ color: '#475569', fontSize: 15 }}>
        {`${score} / ${maxScore} points`}
      </Text>
    </View>
    <View style={{ flexDirection: 'column', gap: 12 }}>
      <PrimaryButton
        label={copy({ de: 'Wróć', en: 'Back to catalog', pl: 'Wróć do katalogu' })}
        onPress={onBackToCatalog}
      />
      <OutlineLink
        href={RESULTS_ROUTE}
        label={copy({ de: 'Wyniki', en: 'See all results', pl: 'Zobacz wyniki' })}
      />
    </View>
  </SectionCard>
);

const TestExplanationView = ({
  currentQuestion,
  selectedChoice,
  correctChoice,
  copy,
}: {
  currentQuestion: KangurMobileTestSuiteItem['questions'][number];
  selectedChoice: KangurMobileTestSuiteItem['questions'][number]['choices'][number] | null;
  correctChoice: KangurMobileTestSuiteItem['questions'][number]['choices'][number] | null;
  copy: KangurMobileCopy;
}): React.JSX.Element => (
  <View
    style={{
      backgroundColor: '#f8fafc',
      borderColor: '#cbd5e1',
      borderRadius: 20,
      borderWidth: 1,
      gap: 8,
      padding: 16,
    }}
  >
    <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '700' }}>
      {selectedChoice?.label === currentQuestion.correctChoiceLabel
        ? copy({ de: 'Dobra', en: 'Correct answer', pl: 'Dobra odpowiedź' })
        : copy({ de: 'Sprawdzona', en: 'Answer reviewed', pl: 'Sprawdzona odpowiedź' })}
    </Text>
    {selectedChoice !== null && (
      <Text style={{ color: '#475569', fontSize: 14 }}>
        {`Wybrano: ${selectedChoice.label}. ${selectedChoice.text}`}
      </Text>
    )}
    {correctChoice !== null && (
      <Text style={{ color: '#475569', fontSize: 14 }}>
        {`Poprawnie: ${correctChoice.label}. ${correctChoice.text}`}
      </Text>
    )}
    {currentQuestion.explanation !== undefined && currentQuestion.explanation.trim().length > 0 && (
      <Text style={{ color: '#334155', fontSize: 14 }}>
        {currentQuestion.explanation.trim()}
      </Text>
    )}
  </View>
);

function KangurMobileTestPlayer({
  item,
  onBackToCatalog,
}: {
  item: KangurMobileTestSuiteItem;
  onBackToCatalog: () => void;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [currentIndex, setCurrentIndex] = useState(0);
  const [finished, setFinished] = useState(false);
  const [revealedAnswers, setRevealedAnswers] = useState<Record<string, boolean>>({});

  const currentQuestion = item.questions[currentIndex] ?? null;
  const selectedLabel = currentQuestion !== null ? (answers[currentQuestion.id] ?? null) : null;
  const isAnswered = selectedLabel !== null;
  const showAnswer = currentQuestion !== null ? Boolean(revealedAnswers[currentQuestion.id]) : false;

  const score = useMemo(() => item.questions.reduce((total, q) =>
    answers[q.id] === q.correctChoiceLabel ? total + q.pointValue : total, 0), [answers, item.questions]);

  const maxScore = useMemo(() => item.questions.reduce((total, q) => total + q.pointValue, 0), [item.questions]);
  const scorePercent = maxScore > 0 ? Math.round((score / maxScore) * 100) : 0;
  const summaryTone = resolveQuestionStatusTone(scorePercent);

  const handleSelect = (label: string): void => {
    if (currentQuestion === null || showAnswer) return;
    setAnswers((p) => ({ ...p, [currentQuestion.id]: label }));
  };

  const handleRevealAnswer = (): void => {
    if (currentQuestion === null || !isAnswered || showAnswer) return;
    setRevealedAnswers((p) => ({ ...p, [currentQuestion.id]: true }));
  };

  const handleNext = (): void => {
    if (currentIndex < item.questions.length - 1) {
      setCurrentIndex((p) => p + 1);
    } else {
      setFinished(true);
    }
  };

  if (finished) {
    return (
      <TestPlayerResultsView
        score={score}
        maxScore={maxScore}
        scorePercent={scorePercent}
        summaryTone={summaryTone}
        onBackToCatalog={onBackToCatalog}
        copy={copy}
      />
    );
  }

  if (currentQuestion === null) return <SectionCard title='Error'><Text>No question.</Text></SectionCard>;

  const selectedChoice = currentQuestion.choices.find((c) => c.label === selectedLabel) ?? null;
  const correctChoice = currentQuestion.choices.find((c) => c.label === currentQuestion.correctChoiceLabel) ?? null;

  return (
    <>
      <SectionCard title={formatQuestionProgress(currentIndex + 1, item.questions.length, locale)}>
        <View style={{ flexDirection: 'row', gap: 8 }}>
          <StatusPill label={formatPointsLabel(currentQuestion.pointValue, locale)} tone={WARNING_TONE} />
        </View>
        <Text style={{ fontSize: 16, fontWeight: '700' }}>{currentQuestion.prompt}</Text>
        <View style={{ gap: 10 }}>
          {currentQuestion.choices.map((choice) => (
            <ChoiceButton
              choice={choice}
              disabled={showAnswer}
              isCorrect={choice.label === currentQuestion.correctChoiceLabel}
              isRevealed={showAnswer}
              isSelected={choice.label === selectedLabel}
              key={choice.label}
              label={choice.label}
              locale={locale}
              onPress={() => { handleSelect(choice.label); }}
            />
          ))}
        </View>
        {showAnswer && <TestExplanationView copy={copy} currentQuestion={currentQuestion} selectedChoice={selectedChoice} correctChoice={correctChoice} />}
        <View style={{ gap: 10 }}>
          <PrimaryButton disabled={!isAnswered || showAnswer} label={copy({ de: 'Prüfen', en: 'Reveal', pl: 'Sprawdź' })} onPress={handleRevealAnswer} />
          <View style={{ flexDirection: 'row', gap: 10 }}>
            <PrimaryButton disabled={currentIndex === 0} label='Prev' onPress={() => setCurrentIndex((p) => p - 1)} tone={BASE_TONE} />
            <PrimaryButton disabled={!showAnswer} label='Next' onPress={handleNext} tone={SUCCESS_TONE} />
          </View>
        </View>
      </SectionCard>
    </>
  );
}

const TestSuiteCard = ({ item, onOpen, copy, locale }: {
  item: KangurMobileTestSuiteItem;
  onOpen: (id: string) => void;
  copy: KangurMobileCopy;
  locale: 'de' | 'en' | 'pl';
}): React.JSX.Element => (
  <SectionCard title={item.suite.title}>
    <View style={{ flexDirection: 'row', gap: 8 }}>
      <StatusPill label={formatQuestionCount(item.questions.length, locale)} tone={INDIGO_TONE} />
      <StatusPill label={formatSuiteMeta(item.suite, locale)[0] ?? ''} tone={BASE_TONE} />
    </View>
    <Text style={{ color: '#475569', fontSize: 14 }}>{item.suite.description}</Text>
    <PrimaryButton label={copy({ de: 'Start', en: 'Start', pl: 'Start' })} onPress={() => onOpen(item.suite.id)} />
  </SectionCard>
);

export function KangurTestsScreen(): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();

  const { suites, isLoading, error, refresh } = useKangurMobileTests();
  const [activeSuiteId, setActiveSuiteId] = useState<string | null>(null);

  const activeSuite = activeSuiteId !== null ? suites.find((s) => s.suite.id === activeSuiteId) ?? null : null;

  if (activeSuite !== null) {
    return (
      <KangurMobileScrollScreen title={activeSuite.suite.title}>
        <KangurMobileTestPlayer item={activeSuite} onBackToCatalog={() => setActiveSuiteId(null)} />
      </KangurMobileScrollScreen>
    );
  }

  return (
    <KangurMobileScrollScreen onRefresh={async () => { await refresh(); }} refreshing={isLoading} title='Tests'>
      {isLoading && <Text>Loading...</Text>}
      {error !== null && <Text>{error}</Text>}
      {suites.map((item) => (
        <TestSuiteCard copy={copy} item={item} key={item.suite.id} locale={locale} onOpen={setActiveSuiteId} />
      ))}
    </KangurMobileScrollScreen>
  );
}

import type { KangurTestChoice } from '@kangur/contracts/kangur-tests';
import { Text } from 'react-native';

import { createKangurLessonsCatalogHref } from '../lessons/lessonHref';
import { createKangurPlanHref } from '../plan/planHref';
import { createKangurPracticeHref } from '../practice/practiceHref';
import { createKangurResultsHref } from '../scores/resultsHref';
import {
  BASE_TONE,
  ChoiceCardButton,
  INDIGO_TONE,
  SUCCESS_TONE,
  WARNING_TONE,
  type Tone,
} from '../shared/KangurAssessmentUi';
import type { KangurMobileLocale } from '../i18n/kangurMobileI18n';
import { formatKangurMobileQuestionCount } from '../shared/questionCountLabel';
import type { KangurMobileTestSuiteItem } from './useKangurMobileTests';
import { createKangurTestsHref } from './testsHref';

export const TESTS_ROUTE = createKangurTestsHref();
export const LESSONS_ROUTE = createKangurLessonsCatalogHref();
export const PRACTICE_ROUTE = createKangurPracticeHref('mixed');
export const PLAN_ROUTE = createKangurPlanHref();
export const RESULTS_ROUTE = createKangurResultsHref();

export const ERROR_TONE: Tone = {
  backgroundColor: '#fef2f2',
  borderColor: '#fecaca',
  textColor: '#b91c1c',
};

export const formatFocusToken = (value: string): string => value.replace(/[-_]+/g, ' ').trim();

export const formatSuiteMeta = (
  suite: KangurMobileTestSuiteItem['suite'],
  locale: KangurMobileLocale,
): string[] => {
  const parts: string[] = [];

  if (typeof suite.year === 'number') {
    parts.push(
      {
        de: `Jahr ${suite.year}`,
        en: `Year ${suite.year}`,
        pl: `Rok ${suite.year}`,
      }[locale],
    );
  }

  if (suite.gradeLevel.trim().length > 0) {
    parts.push(
      {
        de: `Poziom ${suite.gradeLevel}`,
        en: `Level ${suite.gradeLevel}`,
        pl: `Poziom ${suite.gradeLevel}`,
      }[locale],
    );
  }

  if (suite.category.trim().length > 0) {
    parts.push(
      {
        de: `Kategoria ${suite.category}`,
        en: `Category ${suite.category}`,
        pl: `Kategoria ${suite.category}`,
      }[locale],
    );
  }

  return parts;
};

export const formatQuestionProgress = (
  current: number,
  total: number,
  locale: KangurMobileLocale,
): string =>
  ({
    de: `Frage ${current} von ${total}`,
    en: `Question ${current} of ${total}`,
    pl: `Pytanie ${current} z ${total}`,
  })[locale];

export const formatQuestionCount = (
  count: number,
  locale: KangurMobileLocale,
): string => formatKangurMobileQuestionCount(count, locale);

export const formatPointsLabel = (
  value: number,
  locale: KangurMobileLocale,
): string =>
  ({
    de: `${value} Pkt`,
    en: `${value} pts`,
    pl: `${value} pkt`,
  })[locale];

export const resolveQuestionStatusTone = (scorePercent: number): Tone => {
  if (scorePercent >= 80) {
    return SUCCESS_TONE;
  }
  if (scorePercent >= 50) {
    return WARNING_TONE;
  }
  return ERROR_TONE;
};

type ChoiceButtonProps = {
  choice: KangurTestChoice;
  disabled?: boolean;
  isCorrect: boolean;
  isRevealed: boolean;
  isSelected: boolean;
  label: string;
  locale: KangurMobileLocale;
  onPress: () => void;
};

export function ChoiceButton(props: ChoiceButtonProps): React.JSX.Element {
  const {
    choice,
    disabled = false,
    isCorrect,
    isRevealed,
    isSelected,
    label,
    locale,
    onPress,
  } = props;
  const tone = isRevealed
    ? isCorrect
      ? SUCCESS_TONE
      : isSelected
        ? ERROR_TONE
        : BASE_TONE
    : isSelected
      ? INDIGO_TONE
      : BASE_TONE;

  return (
    <ChoiceCardButton
      description={choice.description || undefined}
      disabled={disabled}
      helperText={
        choice.svgContent.trim().length > 0 ? (
          <Text
            style={{
              color: '#64748b',
              fontSize: 12,
              lineHeight: 16,
            }}
          >
            {
              {
                de: 'Diese Antwort hat zusatzliche Illustrationen.',
                en: 'This answer includes extra illustration content.',
                pl: 'Ta odpowiedź ma dodatkową ilustrację.',
              }[locale]
            }
          </Text>
        ) : undefined
      }
      indexLabel={label}
      label={choice.text}
      onPress={onPress}
      tone={tone}
    />
  );
}

import type { Href } from 'expo-router';

export const createKangurTestsHref = (focus?: string | null): Href => {
  const trimmedFocus = focus?.trim();
  if (!trimmedFocus) {
    return '/tests' as Href;
  }

  return ({
    pathname: '/tests',
    params: {
      focus: trimmedFocus,
    },
  }) as unknown as Href;
};

import { KANGUR_TEST_QUESTIONS_SETTING_KEY, KANGUR_TEST_SUITES_SETTING_KEY, kangurTestQuestionStoreSchema, kangurTestSuitesSchema, type KangurTestQuestion, type KangurTestQuestionStore, type KangurTestSuite } from '@kangur/contracts/kangur-tests';
import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';

type KangurLiteSettingRecord = {
  key: string;
  value: string;
};

export type KangurMobileTestSuiteItem = {
  questionCount: number;
  questions: KangurTestQuestion[];
  suite: KangurTestSuite;
};

type UseKangurMobileTestsResult = {
  error: string | null;
  focusToken: string | null;
  focusedSuiteId: string | null;
  isLoading: boolean;
  refresh: () => Promise<void>;
  suites: KangurMobileTestSuiteItem[];
};

const parseJsonValue = <T,>(
  raw: string | undefined,
  parser: {
    safeParse: (value: unknown) => { success: true; data: T } | { success: false };
  },
  fallback: T,
): T => {
  if (typeof raw !== 'string' || raw.trim().length === 0) {
    return fallback;
  }

  try {
    const parsed = parser.safeParse(JSON.parse(raw));
    return parsed.success ? parsed.data : fallback;
  } catch {
    return fallback;
  }
};

const isLiveSuite = (
  suite: Pick<KangurTestSuite, 'enabled' | 'publicationStatus'>,
): boolean => suite.enabled && suite.publicationStatus === 'live';

const isPublishedQuestion = (
  question: Pick<KangurTestQuestion, 'editorial'>,
): boolean => question.editorial.workflowStatus === 'published';

const getPublishedQuestionsForSuite = (
  questionStore: KangurTestQuestionStore,
  suiteId: string,
): KangurTestQuestion[] =>
  Object.values(questionStore)
    .filter(
      (question) => question.suiteId === suiteId && isPublishedQuestion(question),
    )
    .sort((left, right) => {
      const orderDelta = left.sortOrder - right.sortOrder;
      if (orderDelta !== 0) {
        return orderDelta;
      }

      return left.id.localeCompare(right.id);
    });

const resolveFocusedSuiteId = (
  focusToken: string,
  suites: KangurMobileTestSuiteItem[],
): string | null => {
  const normalized = focusToken.trim().toLowerCase();
  if (normalized === '') {
    return null;
  }

  const byId = suites.find((entry) => entry.suite.id.toLowerCase() === normalized);
  if (byId) {
    return byId.suite.id;
  }

  const byTitle = suites.find((entry) =>
    entry.suite.title.toLowerCase().includes(normalized),
  );
  if (byTitle) {
    return byTitle.suite.id;
  }

  const byCategory = suites.find((entry) =>
    entry.suite.category.toLowerCase().includes(normalized),
  );
  if (byCategory) {
    return byCategory.suite.id;
  }

  const byYear = suites.find(
    (entry) =>
      typeof entry.suite.year === 'number' &&
      String(entry.suite.year) === normalized,
  );
  if (byYear) {
    return byYear.suite.id;
  }

  return null;
};

export const useKangurMobileTests = (
  rawFocusToken: string | null,
): UseKangurMobileTestsResult => {
  const { apiBaseUrl } = useKangurMobileRuntime();
  const { copy } = useKangurMobileI18n();
  const focusToken = (rawFocusToken?.trim().toLowerCase()) ?? null;

  const settingsQuery = useQuery({
    queryKey: ['kangur-mobile', 'tests', 'lite-settings', apiBaseUrl],
    queryFn: async (): Promise<KangurLiteSettingRecord[]> => {
      const response = await fetch(`${apiBaseUrl}/api/settings/lite`, {
        cache: 'no-store',
        credentials: 'include',
      });

      if (!response.ok) {
        throw new Error(`Failed to fetch lite settings (${response.status})`);
      }

      const payload = await response.json();
      if (!Array.isArray(payload)) {
        return [];
      }

      return payload.filter(
        (entry): entry is KangurLiteSettingRecord =>
          typeof entry === 'object' &&
          entry !== null &&
          typeof entry['key'] === 'string' &&
          typeof entry['value'] === 'string',
      );
    },
    staleTime: 30_000,
  });

  const suites = useMemo(() => {
    const settingsByKey = new Map(
      (settingsQuery.data ?? []).map((entry) => [entry.key, entry.value]),
    );
    const parsedSuites = parseJsonValue(
      settingsByKey.get(KANGUR_TEST_SUITES_SETTING_KEY),
      kangurTestSuitesSchema,
      [],
    )
      .filter(isLiveSuite)
      .sort((left, right) => {
        const orderDelta = left.sortOrder - right.sortOrder;
        if (orderDelta !== 0) {
          return orderDelta;
        }

        return left.id.localeCompare(right.id);
      });
    const questionStore = parseJsonValue(
      settingsByKey.get(KANGUR_TEST_QUESTIONS_SETTING_KEY),
      kangurTestQuestionStoreSchema,
      {},
    );

    return parsedSuites.map((suite) => {
      const questions = getPublishedQuestionsForSuite(questionStore, suite.id);
      return {
        questionCount: questions.length,
        questions,
        suite,
      };
    });
  }, [settingsQuery.data]);

  return {
    error:
      settingsQuery.error instanceof Error
        ? copy({
            de: 'Die Tests konnten nicht geladen werden.',
            en: 'Could not load the tests.',
            pl: 'Nie udało się pobrać testów.',
          })
        : null,
    focusToken,
    focusedSuiteId:
      focusToken !== null && suites.length > 0
        ? resolveFocusedSuiteId(focusToken, suites)
        : null,
    isLoading: settingsQuery.isLoading,
    refresh: async () => {
      await settingsQuery.refetch();
    },
    suites,
  };
};
